using System;

namespace WelcomeUser
{
    class Program
    {
        static void Main(string[] args)
        {
            // 1. بنطبع رسالة نطلب من المستخدم يدخل اسمه (بدون النزول لسطر جديد عشان يكتب جنبه)
            Console.Write("Enter your name: ");

            // 2. بنقرأ الاسم اللي المستخدم كتبه ونخزنه في متغير نوعه نص (string)
            string name = Console.ReadLine();

            // 3. بنطبع كلمة Hello وبندمج معاها المتغير اللي شايل الاسم باستخدام علامة (+)
            Console.WriteLine("Hello, " + name + "!");
        }
    }
}

using System;

namespace CircleArea
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter the radius of the circle: ");

            // 1. بنقرأ الرقم ونحوله لـ double (عشان نصف القطر ممكن يكون فيه كسور زي 2.5)
            double radius = double.Parse(Console.ReadLine());

            // 2. قاعدة المساحة هي: ط * نق * نق (أو Pi * r * r)
            // استخدمنا Math.PI عشان نجيب قيمة (ط) الدقيقة اللي هي تقريباً 3.14
            double area = Math.PI * radius * radius;

            // 3. بنطبع النتيجة للمستخدم
            Console.WriteLine("Area: " + area);
        }
    }
}

using System;

namespace EvenOrOdd
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int num = int.Parse(Console.ReadLine());

            // 1. علامة (%) معناها "باقي القسمة". 
            // أي رقم زوجي في الدنيا لو قسمناه على 2، مش هيتبقى حاجة (باقي القسمة = صفر)
            if (num % 2 == 0) 
            {
                // لو الشرط اتحقق (الرقم زوجي)
                Console.WriteLine("Even");
            }
            else 
            {
                // لو الشرط متحققش (يبقى أكيد الرقم فردي)
                Console.WriteLine("Odd");
            }
        }
    }
}

using System;

namespace ReverseString
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a word: ");
            string input = Console.ReadLine();

            // 1. بنعمل متغير "فاضي" خالص عشان نحوش فيه الحروف وهي مقلوبة
            string reversed = "";

            // 2. بنعمل حلقة for تمشي بالراجع!
            // البداية: من آخر حرف في الكلمة (اللي هو طول الكلمة ناقص 1، لأن العد بيبدأ من صفر)
            // النهاية: لحد ما نوصل لأول حرف (رقم صفر)
            // الزيادة: هنا بنعمل نقصان (i--) عشان نرجع لورا مش نطلع لقدام
            for (int i = input.Length - 1; i >= 0; i--)
            {
                // 3. كل لفة بنجيب الحرف اللي عليه الدور ونلزقه في الكلمة الفاضية
                reversed = reversed + input[i];
            }

            // 4. بنطبع الكلمة بعد ما اتجمعت بالمقلوب
            Console.WriteLine("Reversed word: " + reversed);
        }
    }
}

using System;

namespace MaximumNumber
{
    class Program
    {
        static void Main(string[] args)
        {
            // 1. دي مصفوفة (Array) فيها شوية أرقام متخزنة جاهزة
            int[] numbers = { 10, 5, 20, 8 };

            // 2. بنفترض مبدئياً إن "أول رقم" هو أكبر رقم لحد ما نثبت العكس
            int max = numbers[0];

            // 3. بنعمل حلقة for تلف على كل الأرقام اللي جوه المصفوفة
            for (int i = 0; i < numbers.Length; i++)
            {
                // 4. بنسأل سؤال: هل الرقم اللي واقفين عليه دلوقتي أكبر من الـ max اللي معانا؟
                if (numbers[i] > max)
                {
                    // لو أكبر، يبقى نغير الـ max ونخليه هو الرقم الجديد ده
                    max = numbers[i];
                }
            }

            // 5. بعد ما الحلقة تخلص وتلف على كل الأرقام، بنطبع أكبر رقم لقيناه
            Console.WriteLine("The maximum number is: " + max);
        }
    }
}

using System;

namespace PalindromeCheck
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a word: ");
            string originalWord = Console.ReadLine();

            // 1. هنجيب الكلمة ونعكسها بنفس الطريقة بتاعة السؤال الرابع بالظبط
            string reversedWord = "";
            for (int i = originalWord.Length - 1; i >= 0; i--)
            {
                reversedWord = reversedWord + originalWord[i];
            }

            // 2. دلوقتي معانا الكلمة الأصلية، والكلمة المقلوبة. هنقارنهم ببعض!
            // لو طلعوا بيساووا بعض بالظبط، يبقى الكلمة دي Palindrome
            if (originalWord == reversedWord)
            {
                Console.WriteLine("Yes! It is a Palindrome.");
            }
            else
            {
                // لو مش بيساووا بعض
                Console.WriteLine("No! It is not a Palindrome.");
            }
        }
    }
}

using System;

namespace RightTriangle
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.WriteLine("--- Star Triangle ---");

            // 1. الحلقة الخارجية: بتتحكم في عدد الصفوف (عايزين 5 صفوف)
            for (int row = 1; row <= 5; row++)
            {
                // 2. الحلقة الداخلية (التريكة هنا): 
                // مش هنثبتها تقف عند 5، إحنا هنخليها تقف عند رقم الصف الحالي (row)
                // يعني لو إحنا في الصف الأول، هتلف لفة وتطبع نجمة. 
                // لو في الصف التاني، هتلف لفتين وتطبع نجمتين، وهكذا.
                for (int col = 1; col <= row; col++)
                {
                    Console.Write("* ");
                }

                // 3. ننزل سطر جديد بعد ما نخلص نجوم الصف الحالي
                Console.WriteLine();
            }
        }
    }
}

using System;

namespace SumOfNumbers
{
    class Program
    {
        static void Main(string[] args)
        {
            Console.Write("Enter a number: ");
            int number = int.Parse(Console.ReadLine());

            // 1. بنعمل "حصالة" عشان نجمع فيها الأرقام
            // بدأناها بصفر لأن الصفر هو المحايد الجمعي (مش هيأثر في الجمع)
            int sum = 0;

            // 2. حلقة بتبدأ من 1 وتقف عند الرقم اللي المستخدم دخله
            for (int i = 1; i <= number; i++)
            {
                // 3. في كل لفة، بناخد قيمة العداد (i) ونحطها جوه الحصالة
                sum = sum + i;
            }

            // 4. بعد ما الحلقة تخلص خالص، بنطبع الحصالة فيها كام
            Console.WriteLine("The sum from 1 to " + number + " is: " + sum);
        }
    }
}

using System;

namespace CalculatePower
{
    class Program
    {
        static void Main(string[] args)
        {
            // 1. بنطلب من المستخدم يدخل الرقم الأساسي (مثلاً 2)
            Console.Write("Enter the base number: ");
            int baseNum = int.Parse(Console.ReadLine());

            // 2. بنطلب منه يدخل الأُس (مثلاً 3، يعني عايزين نضرب الـ 2 في نفسها 3 مرات)
            Console.Write("Enter the power (exponent): ");
            int power = int.Parse(Console.ReadLine());

            // 3. بنعمل "خزنة" للضرب، وبنبدأها بـ 1 (المحايد الضربي)
            int result = 1;

            // 4. بنعمل حلقة بتلف عدد مرات يساوي الـ (power)
            for (int i = 1; i <= power; i++)
            {
                // 5. في كل لفة، بنضرب النتيجة القديمة في الرقم الأساسي
                result = result * baseNum;
            }

            // 6. بنطبع النتيجة النهائية
            Console.WriteLine(baseNum + " to the power of " + power + " = " + result);
        }
    }
}
